css:
.loader {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: #fde047;
  --loader-bg: #ffffff;
  width: 40px;
  aspect-ratio: 1;
  background:linear-gradient(to bottom right,#0000 calc(50% - 40px),var(--loader-bg, #ffffff) 50%,#0000 calc(50% + 40px))bottom right/calc(200% + 80px) calc(200% + 80px)var(--loader-color, #ca8a04);
  animation: l8 1s infinite ;
}@keyframes l8 {100% {background-position: top left}}
